import ComposableArchitecture
import SwiftUI

struct MainView: View {
    @Bindable var store: StoreOf<MainFeature>

    private let calendar = Calendar.current

    var body: some View {
        VStack(spacing: 0) {
            monthHeader
                .padding(.horizontal, 20)
                .padding(.top, 50)
                .padding(.bottom, 20)

            CalendarGrid(
                month: store.currentMonth,
                theme: currentTheme,
                recordedDates: store.recordedDates,
                installDate: store.installDate,
                today: store.today,
                onDayTap: { dayNumber in
                    let date = calendar.date(
                        byAdding: .day,
                        value: dayNumber - 1,
                        to: store.currentMonth.startOfMonth
                    )!
                    store.send(.dayTapped(date))
                }
            )
            .padding(.horizontal, 20)

            Spacer()
        }
        .background(Color(hex: "FAF8F5").ignoresSafeArea())
        .onAppear { store.send(.onAppear) }
    }

    // MARK: - Month Header

    private var monthHeader: some View {
        let year = calendar.component(.year, from: store.currentMonth)
        let month = calendar.component(.month, from: store.currentMonth)

        return VStack(alignment: .leading, spacing: 8) {
            Text(verbatim: String(year))
                .font(.gulim(14))
                .foregroundColor(Color(hex: "AAAAAA"))
                .padding(.top, 3)

            HStack(spacing: 8) {
                Button { store.send(.prevMonthTapped) } label: {
                    Image("icon_arrow_left")
                        .renderingMode(.template)
                        .foregroundColor(canGoPrev ? .black : Color(hex: "D0D0D0"))
                        .padding(.trailing, 12)
                        .padding(.vertical, 10)
                }
                .contentShape(Rectangle())
                .disabled(!canGoPrev)

                Text(verbatim: "\(month)월")
                    .font(.gulim(20))
                    .foregroundColor(.black)

                Button { store.send(.nextMonthTapped) } label: {
                    Image("icon_arrow_right")
                        .renderingMode(.template)
                        .foregroundColor(canGoNext ? .black : Color(hex: "D0D0D0"))
                        .padding(.leading, 12)
                        .padding(.vertical, 10)
                }
                .contentShape(Rectangle())
                .disabled(!canGoNext)

                Spacer()

                HStack(spacing: 12) {
                    Button { store.send(.statisticsTapped) } label: {
                        Image("icon_statistics")
                            .resizable()
                            .renderingMode(.template)
                            .foregroundColor(.black)
                            .frame(width: 20, height: 20)
                    }
                    .buttonStyle(TopRoundButtonStyle())

                    Button { store.send(.exportTapped) } label: {
                        Image("icon_export")
                            .resizable()
                            .renderingMode(.template)
                            .foregroundColor(.black)
                            .frame(width: 20, height: 20)
                    }
                    .buttonStyle(TopRoundButtonStyle())
                }
                .padding(.trailing, 6)
                .offset(y: -8)
            }
        }
    }

    // MARK: - Helpers

    private var currentTheme: MonthlyTheme? {
        let year = calendar.component(.year, from: store.currentMonth)
        let month = calendar.component(.month, from: store.currentMonth)
        return MonthlyTheme.all.first { $0.year == year && $0.month == month }
    }

    private var canGoPrev: Bool {
        let prev = calendar.date(byAdding: .month, value: -1, to: store.currentMonth)!
        return prev >= store.installDate.startOfMonth
    }

    private var canGoNext: Bool {
        let next = calendar.date(byAdding: .month, value: 1, to: store.currentMonth)!
        let maxMonth = calendar.date(byAdding: .month, value: 12, to: store.today)!.startOfMonth
        return next <= maxMonth
    }
}

