import ComposableArchitecture
import Foundation

@Reducer
struct MainFeature {
    @ObservableState
    struct State: Equatable {
        var today: Date = Date()
        var currentMonth: Date = Calendar.current.startOfDay(for: Date()).startOfMonth
        var recordedDates: [Date] = []
        var installDate: Date = Date()
    }

    enum Action {
        case onAppear
        case prevMonthTapped
        case nextMonthTapped
        case dayTapped(Date)
        case diariesLoaded([Date])
        case statisticsTapped
        case exportTapped
    }

    @Dependency(\.diaryClient) var diaryClient

    var body: some Reducer<State, Action> {
        Reduce<State, Action> { state, action in
            switch action {
            case .onAppear:
                #if DEBUG
                let now = state.today
                #else
                let now = Date()
                #endif
                state.today = now
                state.currentMonth = Calendar.current.startOfDay(for: now).startOfMonth
                return loadDiaries(for: state.currentMonth)

            case .prevMonthTapped:
                let prev = Calendar.current.date(byAdding: .month, value: -1, to: state.currentMonth)!
                guard prev >= state.installDate.startOfMonth else { return .none }
                state.currentMonth = prev
                return loadDiaries(for: state.currentMonth)

            case .nextMonthTapped:
                let next = Calendar.current.date(byAdding: .month, value: 1, to: state.currentMonth)!
                let maxMonth = Calendar.current.date(byAdding: .month, value: 12, to: state.today)!.startOfMonth
                guard next <= maxMonth else { return .none }
                state.currentMonth = next
                return loadDiaries(for: state.currentMonth)

            case .dayTapped:
                return .none

            case .diariesLoaded(let dates):
                state.recordedDates = dates
                return .none

            case .statisticsTapped, .exportTapped:
                return .none
            }
        }
    }

    private func loadDiaries(for month: Date) -> Effect<Action> {
        .run { send in
            let dates = (try? await diaryClient.fetchDiaries(month)) ?? []
            await send(.diariesLoaded(dates))
        }
    }
}

extension MainFeature.State {
    init(today: Date, currentMonth: Date? = nil, installDate: Date) {
        self.today = today
        self.currentMonth = currentMonth ?? Calendar.current.startOfDay(for: today).startOfMonth
        self.installDate = installDate
        self.recordedDates = []
    }
}

