import SwiftUI

enum DotState: Equatable {
    case recorded(cell: PixelArtCell)
    case future(cell: PixelArtCell, dayNumber: Int)
    case missed(cell: PixelArtCell, dayNumber: Int)
    case preInstall(cell: PixelArtCell)
    case padding(cell: PixelArtCell)
}

struct DotCircle: View {
    let state: DotState
    var isToday: Bool = false

    private let size: CGFloat = 50

    private var baseCell: PixelArtCell {
        switch state {
        case .recorded(let c): return c
        case .future(let c, _): return c
        case .missed(let c, _): return c
        case .preInstall(let c): return c
        case .padding(let c): return c
        }
    }

    private var circleBackground: Color {
        switch state {
        case .recorded, .preInstall, .padding:
            return baseCell.backgroundColor
        case .future:
            return Color(hex: "EDECE9")
        case .missed:
            return baseCell.backgroundColor.opacity(0.4)
        }
    }

    private var displayText: String? {
        switch state {
        case .recorded(let cell):
            return cell.text
        case .future(_, let day):
            return "\(day)"
        case .missed(_, let day):
            return "\(day)"
        case .preInstall, .padding:
            return nil
        }
    }

    private var textColor: Color {
        if isToday { return Color(hex: "504D4D") }
        switch state {
        case .recorded(let cell):
            return cell.textColor
        case .future:
            return Color(hex: "BBBBBB")
        case .missed(let cell, _):
            return cell.textColor
        case .preInstall, .padding:
            return .clear
        }
    }

    private var textFont: Font {
        switch state {
        case .recorded:
            return .meetme(24)
        default:
            return .gulim(18)
        }
    }

    var body: some View {
        ZStack {
            Circle()
                .fill(circleBackground)
                .frame(width: size, height: size)

            // Image layer for image-based pixel art cells
            if case .recorded(let cell) = state, let imageName = cell.imageName {
                Image(imageName)
                    .resizable()
                    .scaledToFill()
                    .frame(width: size, height: size)
                    .clipShape(Circle())
            }

            // Dashed inner stroke for missed days
            if case .missed(let cell, _) = state {
                Circle()
                    .strokeBorder(
                        cell.backgroundColor.opacity(0.7),
                        style: StrokeStyle(lineWidth: 1.5, dash: [3, 2])
                    )
                    .frame(width: size - 8, height: size - 8)
            }

            // Text overlay
            if let text = displayText, !text.isEmpty {
                Text(text)
                    .font(textFont)
                    .foregroundColor(textColor)
            }
        }
        .frame(width: size, height: size)
